#!/usr/bin/env bash
# sop-sop.sh — 朋友圈 SOP：发圈内容矩阵与节奏（核心 SOP） SOP walkthrough for 微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变)"
WORKFLOW="朋友圈 SOP：发圈内容矩阵与节奏（核心 SOP）"

usage() {
  cat <<EOF
sop-sop.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sop-sop.sh             # interactive
  ./sop-sop.sh --dry-run
  ./sop-sop.sh --json
  ./sop-sop.sh --explain
  ./sop-sop.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "朋友圈 SOP：发圈内容矩阵与节奏（核心 SOP）" 工作流。

一句话: 把企微 / 个人号的朋友圈从「想起来才发、全是硬广」变成「有人设、有内容矩阵、有固定节奏的标准化运营」，让朋友圈成为持续建立信任、低成本反复触达的阵地，而不是被用户屏蔽。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 公私二分 / 流量自主权（mental model）: 私域人看一切流量的底层镜片是「这部分流量是租来的还是自己的」——租来的（公域）用一次付一次、平台控分发，自己的（私域）可反复免费触达；近年这对二分从「对立」演化为「全域协同」，但「自主权」这条轴没变。
  • 流量池 / 蓄水养鱼（mental model）: 私域人把流量当成「要蓄进池子、反复经营」的对象而非「这次能转化多少」的一次性曝光——但「建了群 / 加了好友」只是蓄了水，**没有运营动作的池是死水**；价值在「蓄水—养鱼—捕鱼」的循环，不在池子大小

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定人设 + 内容三维度**：以「业务 + 产品 + 人设」为核心，确定发圈的内容维度、思路和频次。who: 操盘手 / 账号运营人。(evidence: [T03-S005], [T03-S010])"
  "**搭内容矩阵**：内容分三大维度——用户相关（干货知识 / 互动内容）、人设相关（生活日常 / 工作学习 / 生活态度）、产品相关（产品服务 / 用户口碑 / 荣誉权威 / 限时活动），三类按比例搭配。(evidence: [T03-S005])"
  "**定频率**：每天 3-5 条为佳（品类内容少则 2-3 条）；发太多易被用户屏蔽 / 删除。(evidence: [T03-S005])"
  "**排周内容表**：以周为单位提前做朋友圈内容策划表，准备好对应文案 / 素材，形成标准作业程序。(evidence: [T03-S005], [T03-S010])"
  "**发布 + 多账号微调**：按表发布；若多账号同发一套素材，需微调文案 / 图片并错开时间，否则被系统判定批量、触发屏蔽。(evidence: [T03-S005])"
  "**互动 + 迭代**：对朋友圈下的评论 / 点赞做互动（朋友圈是双向的），并按互动 / 转化反馈迭代内容表。"
)
declare -a FAILURE_MODES=(
  "**高频硬广刷屏被屏蔽**: 触发原因 = 把朋友圈当免费广告位、产品圈占比过高 + 频率过高。怎么避免 = 控制产品硬广比例、每天 3-5 条上限、用价值 + 人设内容养住「愿意看」。"
  "**多账号同素材被判批量**: 触发原因 = 矩阵号偷懒同发一套素材。怎么避免 = 多账号必须微调文案 / 图片 + 错开发布时间。"
  "**CLI 化暗示 (v0.6+)**: Post 8+ product ads a day across the same template — users mute you en masse, and a muted contact is a dead touchpoint forever. 每天 3-5 条上限，产品硬广控制在矩阵的一小部分。"
  "**CLI 化暗示 (v0.6+)**: Blast the identical Moments asset from five matrix accounts at the same time — WeChat flags it as batch marketing and throttles you. 多账号必须微调素材 + 错峰。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sop-sop-walkthrough"
fi
